import{_ as r,o as i,c as o,a2 as a}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"🫘 黃豆追蹤日報 — 2026-05-18（週一）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-18.md","filePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-18.md"}'),l={name:"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-18.md"};function n(s,t,e,d,g,h){return i(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="🫘-黃豆追蹤日報-—-2026-05-18-週一" tabindex="-1">🫘 黃豆追蹤日報 — 2026-05-18（週一） <a class="header-anchor" href="#🫘-黃豆追蹤日報-—-2026-05-18-週一" aria-label="Permalink to &quot;🫘 黃豆追蹤日報 — 2026-05-18（週一）&quot;">​</a></h1><blockquote><p>查詢時間：2026-05-18 05:00 TST（2026-05-17 21:00 UTC） 報告類型：每日追蹤 ⚠️ CBOT 期貨時段說明：05:00 TST 週一凌晨 = 17:00 ET 週日，黃豆期貨已收盤（最後交易日 5/15 週五）</p></blockquote><hr><h2 id="📊-即時報價" tabindex="-1">📊 即時報價 <a class="header-anchor" href="#📊-即時報價" aria-label="Permalink to &quot;📊 即時報價&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指標</th><th>報價</th><th>日漲跌</th><th>查詢時間</th><th>來源</th></tr></thead><tbody><tr><td>CBOT 黃豆 Jul 2026 (ZS=F)</td><td>1,177 USd/Bu</td><td>-15.50¢ (-1.30%)</td><td>2026-05-15 16:00 ET</td><td>TradingEconomics</td></tr><tr><td>CBOT 黃豆 Nov 2026 (ZSX26)</td><td>~1,165¢（估算）</td><td>—</td><td>2026-05-15</td><td>TradingEconomics</td></tr><tr><td>WTI 原油</td><td>$105.42/桶</td><td>+$4.25 (+4.20%)</td><td>2026-05-15</td><td>TradingEconomics</td></tr><tr><td>Brent 原油</td><td>$109.26/桶</td><td>+$3.46 (+3.26%)</td><td>2026-05-15</td><td>TradingEconomics</td></tr><tr><td>DXY 美元指數</td><td>99.27</td><td>+0.46</td><td>2026-05-15</td><td>TradingEconomics</td></tr><tr><td>尿素</td><td>$577/噸</td><td>+$4.50 (+0.79%)</td><td>2026-05-15</td><td>TradingEconomics</td></tr><tr><td>天然氣 Henry Hub</td><td>$2.96/MMBtu</td><td>+$0.066 (+2.28%)</td><td>2026-05-15</td><td>TradingEconomics</td></tr><tr><td>波羅的海乾散貨指數 BDI</td><td>3,151</td><td>週漲 5.8%</td><td>2026-05-15</td><td>TradingEconomics</td></tr></tbody></table><blockquote><p><strong>查詢時間（TST）</strong>：2026-05-18 05:00</p></blockquote><hr><h2 id="🔍-敘事延續-川習會「preliminary」-中國承諾-17b-年農產品-荷莫茲成本壓力" tabindex="-1">🔍 敘事延續：川習會「preliminary」+ 中國承諾 $17B/年農產品 + 荷莫茲成本壓力 <a class="header-anchor" href="#🔍-敘事延續-川習會「preliminary」-中國承諾-17b-年農產品-荷莫茲成本壓力" aria-label="Permalink to &quot;🔍 敘事延續：川習會「preliminary」+ 中國承諾 $17B/年農產品 + 荷莫茲成本壓力&quot;">​</a></h2><p><strong>本日核心</strong>：黃豆收在 1,177 USd/Bu（-1.30%），連續第二日下跌。週末關鍵更新：White House 公布川習會事實清單，中國承諾 2026-2028 每年購買 $17B 美國農產品（含黃豆），但中國商務部定性為「preliminary」。USDA 種植進度 49% 領先五年均值 36%。巴西 StoneX 下修產量至 177.8M 噸（乾旱），但仍是紀錄水平。荷莫茲海峽持續封閉推升能源成本，BDI 月漲 25% 反映運費上升。</p><hr><h2 id="_8-項追蹤指標" tabindex="-1">8 項追蹤指標 <a class="header-anchor" href="#_8-項追蹤指標" aria-label="Permalink to &quot;8 項追蹤指標&quot;">​</a></h2><h3 id="_1-usda-種植進度報告-每週" tabindex="-1">1. USDA 種植進度報告（每週） <a class="header-anchor" href="#_1-usda-種植進度報告-每週" aria-label="Permalink to &quot;1. USDA 種植進度報告（每週）&quot;">​</a></h3><ul><li><strong>種植進度</strong>（截至 5/10）：49% 黃豆已播種（前週 33%），高於五年均值 36%</li><li><strong>出芽率</strong>：20% 已出芽（五年均值 12%）</li><li><strong>個別州</strong>：Illinois 57%、Iowa 60%、Indiana 51%</li><li><strong>WASDE 5/12</strong>：2026/27 終庫存 310M bu（低於預期 ~355M），壓榨 2.75B bu（連續 6 年創紀錄）</li><li><strong>變化</strong>：🟡 種植進度良好 — 下週 expected 60%+ 播種</li><li><strong>查詢時間</strong>：2026-05-15</li><li>來源：RFD TV (2026-05-15)、Agronews (2026-05-15)、Farm Progress (2026-05-12)</li></ul><h3 id="_2-巴西供應-收割-出口-豐收" tabindex="-1">2. 巴西供應（收割 + 出口 + 豐收） <a class="header-anchor" href="#_2-巴西供應-收割-出口-豐收" aria-label="Permalink to &quot;2. 巴西供應（收割 + 出口 + 豐收）&quot;">​</a></h3><ul><li><strong>CONAB</strong>（5 月）：2025/26 產量 180.13M 噸（+0.5% vs 前估，+5% YoY）</li><li><strong>StoneX</strong>（5 月）：下修至 177.8M 噸（從 181.6M），南大河乾旱</li><li><strong>出口</strong>：CONAB 預測 116M 噸（+7.25% YoY）</li><li><strong>2026/27 展望</strong>：USDA 預估巴西產量 186M 噸（+8M vs 本季）</li><li><strong>挑戰</strong>：物流（60% 靠卡車、14% 公路鋪設）、中巴植物檢疫爭議、國內壓榨需求上升</li><li><strong>變化</strong>：🟡 無重大變化 — 本季已收割完成，關注下季播種</li><li><strong>查詢時間</strong>：2026-05-17</li><li>來源：CONAB (2026-05)、StoneX/Biofuels Digest (2026-05)、CEIC Data (2026-05)、Farm Progress (2026-05)</li></ul><h3 id="_3-尿素價格-多單訊號" tabindex="-1">3. 尿素價格 + 多單訊號 <a class="header-anchor" href="#_3-尿素價格-多單訊號" aria-label="Permalink to &quot;3. 尿素價格 + 多單訊號&quot;">​</a></h3><ul><li><strong>尿素</strong>：$577/噸（+0.79%），月跌 19.07% 但年漲 21.79%</li><li><strong>尿素 FOB 美灣</strong>：$586.25/噸（5/15）</li><li><strong>零售均價</strong>：$865/噸（5 月第一週），年漲 39%</li><li><strong>化肥成本</strong>：荷莫茲海峽封鎖 → 全球 ~30% 化肥出口受影響 → 成本持續高檔</li><li><strong>變化</strong>：🟡 成本高檔但月跌 19% — 短期壓力紓解但長期結構性上升</li><li><strong>查詢時間</strong>：2026-05-15</li><li>來源：TradingEconomics (2026-05-15)、DTN/Progressive Farmer (2026-05-13)</li></ul><h3 id="_4-荷莫茲海峽通航狀態" tabindex="-1">4. 荷莫茲海峽通航狀態 <a class="header-anchor" href="#_4-荷莫茲海峽通航狀態" aria-label="Permalink to &quot;4. 荷莫茲海峽通航狀態&quot;">​</a></h3><ul><li>🔴 <strong>持續惡化</strong>：海峽實質封閉，伊朗宣布「管理機制」</li><li><strong>伊朗 Azizi</strong>（5/17）：將公布「professional mechanism to manage maritime traffic」，對合規船隻收費，不再允許「敵方」軍事設備通過</li><li><strong>歐洲</strong>：多國已與德黑蘭洽談船隻通行（Egypt Today 5/17）</li><li><strong>CENTCOM</strong>：70+ 艘商業船被改道，4 艘被扣押</li><li><strong>伊拉克</strong>：4 月出口僅 10M 桶（戰前月均 93M），暴跌 90%</li><li><strong>專家預測</strong>：海峽恢復正常通航至少需 4-6 個月</li><li><strong>對黃豆影響</strong>：能源成本飆漲 → 農業生產成本上升 → 間接支撐價格底部；但巴西出口物流受阻可能讓出市場份額給美國</li><li><strong>變化</strong>：🔴 <strong>持續惡化</strong> — 伊朗「管理機制」細節待觀察</li><li><strong>查詢時間</strong>：2026-05-17</li><li>來源：Gulf News (2026-05-17)、Egypt Today (2026-05-17)、Maritime Executive (2026-05-16)</li></ul><h3 id="_5-中美貿易-中國進口" tabindex="-1">5. 中美貿易 + 中國進口 <a class="header-anchor" href="#_5-中美貿易-中國進口" aria-label="Permalink to &quot;5. 中美貿易 + 中國進口&quot;">​</a></h3><ul><li>🔴 <strong>關鍵更新</strong>：White House 公布事實清單，中國承諾 $17B/年農產品</li><li><strong>White House</strong>（5/17）：中國承諾 2026-2028 每年購買 $17B 美國農產品（含黃豆、玉米、豬肉、牛肉、家禽）</li><li><strong>中國商務部</strong>（5/16）：定性為「preliminary」，需「finalised as soon as possible」</li><li><strong>S&amp;P Global</strong>：年初至今美國對華黃豆銷售年減 48%</li><li><strong>關稅</strong>：市場預期 10% 黃豆關稅將下調，可能允許中國私營壓榨廠恢復採購</li><li><strong>關鍵時間點</strong>：9-10 月美國黃豆收成季，若中國不在此期間增加採購，出口復甦夢碎</li><li><strong>變化</strong>：🔴 <strong>關鍵進展</strong> — $17B 承諾是正面信號，但「preliminary」定性降低短期期望</li><li><strong>查詢時間</strong>：2026-05-17</li><li>來源：White House (2026-05)、Seeking Alpha (2026-05-17)、SCMP (2026-05-16)、S&amp;P Global (2026-05-14)</li></ul><h3 id="_6-天然氣價格" tabindex="-1">6. 天然氣價格 <a class="header-anchor" href="#_6-天然氣價格" aria-label="Permalink to &quot;6. 天然氣價格&quot;">​</a></h3><ul><li><strong>Henry Hub</strong>：$2.96/MMBtu（+2.28%），接近七週高</li><li><strong>EIA 注入</strong>：85 bcf（符合預期），低於去年同期 109 bcf</li><li><strong>供給</strong>：EQT 等削減產出，日產量降至 15 週低</li><li><strong>出口</strong>：LNG 出口從 4 月紀錄 18.8 bcfd 降至 5 月 ~17.0 bcfd（季節性維護）</li><li><strong>EIA 預測</strong>：下調 2026 年現貨預測至 $3.50/MMBtu</li><li><strong>變化</strong>：🟡 無重大變化 — 供給偏緊但需求季節性低</li><li><strong>查詢時間</strong>：2026-05-15</li><li>來源：TradingEconomics (2026-05-15)、AGA (2026-05-15)</li></ul><h3 id="_7-聖嬰-拉尼娜氣候風險" tabindex="-1">7. 聖嬰/拉尼娜氣候風險 <a class="header-anchor" href="#_7-聖嬰-拉尼娜氣候風險" aria-label="Permalink to &quot;7. 聖嬰/拉尼娜氣候風險&quot;">​</a></h3><ul><li><strong>變化</strong>：⚪ 本日無重大更新 — 待下季氣候報告</li><li><strong>查詢時間</strong>：2026-05-18</li></ul><h3 id="_8-cbot-價格區間-海運成本" tabindex="-1">8. CBOT 價格區間 + 海運成本 <a class="header-anchor" href="#_8-cbot-價格區間-海運成本" aria-label="Permalink to &quot;8. CBOT 價格區間 + 海運成本&quot;">​</a></h3><ul><li><strong>Jul 2026</strong>：1,177 USd/Bu（-1.30%），本週跌約 3%</li><li><strong>技術面</strong>：從 5/12 WASDE 後高點 ~1,210 回落，支撐 1,150-1,160</li><li><strong>BDI（波羅的海乾散貨指數）</strong>：3,151（5/15），月漲 24.89%，年漲 127%</li><li><strong>Capesize</strong>：5,316（-2.3%），但週漲強勁</li><li><strong>Panamax</strong>：2,521（+0.7%），運費持續上升</li><li><strong>影響</strong>：BDI 飆升反映全球運費上升，增加黃豆出口成本</li><li><strong>變化</strong>：🟡 延續跌勢 — 川習會無實質突破 + 運費上升</li><li><strong>查詢時間</strong>：2026-05-17</li><li>來源：TradingEconomics (2026-05-15/17)</li></ul><hr><h2 id="📰-即時新聞-5-條" tabindex="-1">📰 即時新聞（5 條） <a class="header-anchor" href="#📰-即時新聞-5-條" aria-label="Permalink to &quot;📰 即時新聞（5 條）&quot;">​</a></h2><ol><li><strong>White House (2026-05-17)</strong>：Fact sheet — China commits $17B/year in US ag purchases, Boeing 200+ aircraft, rare earth minerals</li><li><strong>Seeking Alpha (2026-05-17)</strong>：China pledges $17B in US farm purchases as trade talks resume</li><li><strong>CONAB (2026-05)</strong>：Brazil soybean production 180.13M tons (+5% YoY)</li><li><strong>Gulf News (2026-05-17)</strong>：Iran plans Hormuz transit fees, bars &quot;enemy&quot; military equipment</li><li><strong>Egypt Today (2026-05-17)</strong>：European states in talks with Iran over Hormuz ship transit</li></ol><hr><h2 id="📊-情景分析" tabindex="-1">📊 情景分析 <a class="header-anchor" href="#📊-情景分析" aria-label="Permalink to &quot;📊 情景分析&quot;">​</a></h2><table tabindex="0"><thead><tr><th>情境</th><th>發生機率</th><th>價格影響</th><th>傳導機制</th></tr></thead><tbody><tr><td>中國 6 月下調黃豆 10% 關稅 + $17B 實際執行</td><td>50%</td><td>+5-8%（至 ~1,235-1,270¢）</td><td>私營壓榨廠恢復採購 → 需求大增</td></tr><tr><td>荷莫茲海峽 6 月重開</td><td>20%</td><td>-5-8%（至 ~1,080-1,120¢）</td><td>能源成本下降 → 農業成本壓力紓解</td></tr><tr><td>海峽持續封閉 + 中國延遲關稅下調</td><td>45%</td><td>持平至 -2%（1,150-1,180¢）</td><td>能源成本高檔支撐底部 vs 需求疲軟壓制</td></tr><tr><td>巴西下季播種因乾旱延遲</td><td>25%</td><td>+3-5%（至 ~1,210-1,235¢）</td><td>全球供應擔憂 → 投機買盤</td></tr></tbody></table><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>TradingEconomics (2026-05-15): Soybeans 1,177, WTI $105.42, Natural Gas $2.96, Urea $577, BDI 3,151</li><li>White House (2026-05-17): Fact sheet — Trump secures historic deals with China</li><li>Seeking Alpha (2026-05-17): China pledges $17B in US farm purchases</li><li>SCMP (2026-05-16): Soybean counters — scope of China-US farm deal</li><li>S&amp;P Global (2026-05-14): US soybean sales to China fall 48% YTD</li><li>CONAB (2026-05): Brazil soybean production 180.13M tons</li><li>StoneX/Biofuels Digest (2026-05): Brazil harvest cut to 177.8M tons</li><li>Farm Progress (2026-05-12): USDA crop progress 49% planted</li><li>RFD TV (2026-05-15): Corn and soybean planting ahead of schedule</li><li>Gulf News (2026-05-17): Iran plans Hormuz transit mechanism</li><li>Egypt Today (2026-05-17): European states in talks with Iran</li><li>AGA (2026-05-15): Natural gas market indicators</li><li>DTN/Progressive Farmer (2026-05-13): Fertilizer prices higher</li></ol>',36)])])}const m=r(l,[["render",n]]);export{c as __pageData,m as default};
